module top_module(
    input [7:0] a, b, c, d,
    output [7:0] min);reg [7:0] max_val_1, stage2_out, stage3_out;

    // Stage 1
    always @(*) begin
        if (a < b)
            max_val_1 = a;
        else
            max_val_1 = b;
    end

    // Stage 2
    always @(*) begin
        if (c < d)
            stage2_out = c;
        else
            stage2_out = d;
    end

    // Stage 3
    always @(*) begin
        if (max_val_1 < stage2_out)
            stage3_out = max_val_1;
        else
            stage3_out = stage2_out;
    end

    // Output
    assign min = stage3_out;

endmodule
